import sys
from functools import lru_cache

class Solution:
    def maxCollectedFruits(self, fruits):
        n = len(fruits)
        sys.setrecursionlimit(10000)
        NEG = float('-inf')

        @lru_cache(maxsize=None)
        def rec(t, j2, i3):
            i1 = j1 = t
            i2 = t
            j3 = t
            cells = {(i1, j1), (i2, j2), (i3, j3)}
            gain = sum(fruits[a][b] for a, b in cells)
            if t == n - 1:
                if j2 == n - 1 and i3 == n - 1:
                    return gain
                return NEG
            best = NEG
            for dj2 in (-1, 0, 1):
                nj2 = j2 + dj2
                if not (0 <= nj2 < n):
                    continue
                for di3 in (-1, 0, 1):
                    ni3 = i3 + di3
                    if not (0 <= ni3 < n):
                        continue
                    sub = rec(t + 1, nj2, ni3)
                    if sub > best:
                        best = sub
            if best == NEG:
                return NEG
            return gain + best

        return rec(0, n - 1, n - 1)

