class Solution:
    def maxCollectedFruits(self, fruits):
        n = len(fruits)
        NEG = -1 << 60
        total = sum(fruits[i][i] for i in range(n))
        g = [row[:] for row in fruits]
        for i in range(n):
            g[i][i] = 0

        dp2 = [[NEG] * n for _ in range(n)]
        dp2[0][n - 1] = g[0][n - 1]
        for i in range(1, n):
            for j in range(n):
                best = NEG
                for dj in (-1, 0, 1):
                    pj = j + dj
                    if 0 <= pj < n and dp2[i - 1][pj] > best:
                        best = dp2[i - 1][pj]
                dp2[i][j] = g[i][j] + best if best > NEG else NEG

        dp3 = [[NEG] * n for _ in range(n)]
        dp3[n - 1][0] = g[n - 1][0]
        for j in range(1, n):
            for i in range(n):
                best = NEG
                for di in (-1, 0, 1):
                    pi = i + di
                    if 0 <= pi < n and dp3[pi][j - 1] > best:
                        best = dp3[pi][j - 1]
                dp3[i][j] = g[i][j] + best if best > NEG else NEG

        return total + dp2[n - 1][n - 1] + dp3[n - 1][n - 1]

