var maxCollectedFruits = function(fruits) {
    const n = fruits.length;
    const NEG = -Infinity;
    let total = 0;
    for (let i = 0; i < n; i++) total += fruits[i][i];
    const g = fruits.map(row => row.slice());
    for (let i = 0; i < n; i++) g[i][i] = 0;

    const dp2 = Array.from({ length: n }, () => new Array(n).fill(NEG));
    dp2[0][n - 1] = g[0][n - 1];
    for (let i = 1; i < n; i++) {
        for (let j = 0; j < n; j++) {
            let best = NEG;
            for (const dj of [-1, 0, 1]) {
                const pj = j + dj;
                if (pj >= 0 && pj < n && dp2[i - 1][pj] > best) best = dp2[i - 1][pj];
            }
            dp2[i][j] = best > NEG ? g[i][j] + best : NEG;
        }
    }

    const dp3 = Array.from({ length: n }, () => new Array(n).fill(NEG));
    dp3[n - 1][0] = g[n - 1][0];
    for (let j = 1; j < n; j++) {
        for (let i = 0; i < n; i++) {
            let best = NEG;
            for (const di of [-1, 0, 1]) {
                const pi = i + di;
                if (pi >= 0 && pi < n && dp3[pi][j - 1] > best) best = dp3[pi][j - 1];
            }
            dp3[i][j] = best > NEG ? g[i][j] + best : NEG;
        }
    }

    return total + dp2[n - 1][n - 1] + dp3[n - 1][n - 1];
};
